import{_ as a,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"156. Nauseous Work Allowance","description":"","frontmatter":{"title":"156. Nauseous Work Allowance","eba":"Mental Health Services 2024-2028","topics":["allowances","preliminary","classifications"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/156-nauseous-work-allowance.md","filePath":"ebas/mental-health/support-services/preliminary/156-nauseous-work-allowance.md"}'),l={name:"ebas/mental-health/support-services/preliminary/156-nauseous-work-allowance.md"};function r(t,e,i,u,c,h){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_156-nauseous-work-allowance" tabindex="-1">156. Nauseous Work Allowance <a class="header-anchor" href="#_156-nauseous-work-allowance" aria-label="Permalink to &quot;156. Nauseous Work Allowance&quot;">​</a></h1><p><strong>156.1</strong> Employees shall be paid a Nauseous Work Allowance pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for all time during which they are engaged in handling linen of a nauseous nature, other than linen sealed in airtight containers.</p><p><strong>156.2</strong> The Allowance shall be paid to an Employee in any classification for work that is of an unusually dirty or offensive nature having regard to the duty normally performed by such Employee in such classification. Provided that, an Employee who is paid the nauseous work allowance prescribed in clause 156.1, shall not be entitled to be paid an allowance under clause 156.2 for the same work.</p><p><strong>156.3</strong> The nauseous work allowance is payable per hour, or part thereof, in addition to the rates prescribed elsewhere in Section 4. The weekly allowance is the minimum amount payable for work performed in any week.</p><p><strong>156.4</strong> The rounding provision does not apply to the calculation of the hourly rate of this allowance.</p>',5)])])}const w=a(l,[["render",r]]);export{d as __pageData,w as default};
